import os
import pickle
import hashlib
import uuid
from flask import Flask, request, jsonify, send_file
from werkzeug.utils import secure_filename
import joblib
import numpy as np
from sklearn.base import BaseEstimator, TransformerMixin
import logging

app = Flask(__name__)
app.config['MAX_CONTENT_LENGTH'] = 100 * 1024 * 1024  # 100MB max file size
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MODELS_FOLDER'] = 'models'

# Create directories
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)
os.makedirs(app.config['MODELS_FOLDER'], exist_ok=True)

# Safe deserialization with restricted imports
class SafeUnpickler(pickle.Unpickler):
    def find_class(self, module, name):
        # Allow only specific safe modules and classes
        safe_modules = {
            'numpy', 'numpy.core.multiarray', 'numpy.core._methods',
            'sklearn.base', 'sklearn.preprocessing', 'sklearn.ensemble',
            'sklearn.linear_model', 'sklearn.tree', 'sklearn.svm',
            'sklearn.neighbors', 'sklearn.naive_bayes', 'sklearn.metrics',
            'joblib', 'builtins'
        }
        
        if module not in safe_modules:
            raise pickle.UnpicklingError(f"Module {module} not allowed")
            
        # Restrict specific classes
        restricted_classes = {
            'numpy.ndarray', 'numpy.core.multiarray.ndarray',
            'sklearn.base.BaseEstimator', 'sklearn.base.TransformerMixin'
        }
        
        if f"{module}.{name}" in restricted_classes:
            return super().find_class(module, name)
        elif module == 'builtins':
            if name in ['list', 'dict', 'tuple', 'str', 'int', 'float', 'bool']:
                return super().find_class(module, name)
            else:
                raise pickle.UnpicklingError(f"Class {name} not allowed")
        else:
            raise pickle.UnpicklingError(f"Class {module}.{name} not allowed")

# Custom safe load function
def safe_load_model(file_path):
    with open(file_path, 'rb') as f:
        # Check file integrity
        file_hash = hashlib.md5(f.read()).hexdigest()
        f.seek(0)
        
        # Use custom unpickler
        unpickler = SafeUnpickler(f)
        model = unpickler.load()
        
        # Verify model type
        if not hasattr(model, 'predict'):
            raise ValueError("Model must have a predict method")
            
        return model, file_hash

# Model registry
model_registry = {}

@app.route('/upload_model', methods=['POST'])
def upload_model():
    try:
        if 'model' not in request.files:
            return jsonify({'error': 'No model file provided'}), 400
            
        file = request.files['model']
        if file.filename == '':
            return jsonify({'error': 'No file selected'}), 400
            
        if file:
            filename = secure_filename(file.filename)
            unique_id = str(uuid.uuid4())
            model_path = os.path.join(app.config['UPLOAD_FOLDER'], f"{unique_id}_{filename}")
            
            file.save(model_path)
            
            # Validate and load model
            model, model_hash = safe_load_model(model_path)
            
            # Store in registry
            model_registry[unique_id] = {
                'model': model,
                'hash': model_hash,
                'name': filename,
                'created_at': str(np.datetime64('now'))
            }
            
            # Move to models folder
            final_path = os.path.join(app.config['MODELS_FOLDER'], f"{unique_id}_{filename}")
            os.rename(model_path, final_path)
            
            return jsonify({
                'model_id': unique_id,
                'message': 'Model uploaded successfully',
                'model_name': filename
            }), 200
            
    except Exception as e:
        logging.error(f"Error uploading model: {str(e)}")
        return jsonify({'error': str(e)}), 500

@app.route('/predict/<model_id>', methods=['POST'])
def predict(model_id):
    try:
        if model_id not in model_registry:
            return jsonify({'error': 'Model not found'}), 404
            
        model = model_registry[model_id]['model']
        data = request.get_json()
        
        if 'input' not in data:
            return jsonify({'error': 'Input data required'}), 400
            
        input_data = np.array(data['input'])
        
        # Ensure input is 2D for sklearn models
        if input_data.ndim == 1:
            input_data = input_data.reshape(1, -1)
            
        prediction = model.predict(input_data)
        
        return jsonify({
            'prediction': prediction.tolist()
        }), 200
        
    except Exception as e:
        logging.error(f"Error during prediction: {str(e)}")
        return jsonify({'error': str(e)}), 500

@app.route('/models', methods=['GET'])
def list_models():
    try:
        models = []
        for model_id, info in model_registry.items():
            models.append({
                'id': model_id,
                'name': info['name'],
                'created_at': info['created_at']
            })
        return jsonify({'models': models}), 200
    except Exception as e:
        logging.error(f"Error listing models: {str(e)}")
        return jsonify({'error': str(e)}), 500

@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy'}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)